use std::collections::HashMap;

struct GameAsset {
    name: String,
    id: u32,
}

fn process_and_regroup_assets(list_a: Vec<String>, list_b: Vec<u32>) -> (Vec<(String, u32)>, HashMap<String, Vec<u32>>) {
    let zipped_pairs: Vec<(String, u32)> = list_a.into_iter().zip(list_b.into_iter()).collect();

    let mut regrouped_map: HashMap<String, Vec<u32>> = HashMap::new();

    for (name, id) in zipped_pairs.iter() {
        regrouped_map.entry(name.clone()).or_default().push(*id);
    }

    let final_pairs: Vec<(String, u32)> = zipped_pairs;
    (final_pairs, regrouped_map)
}

use std::collections::HashMap;

struct SensorReading {
    temperature: f32,
    humidity: f32,
    voltage: f32,
}

fn main() {
    let temps = vec![20.5, 21.0, 19.8];
    let hums = vec![60.2, 61.5, 59.0];
    let vols = vec![3.7, 3.65, 3.8];

    let combined_readings: Vec<SensorReading> = temps.into_iter()
        .zip(hums.into_iter())
        .zip(vols.into_iter())
        .map(|((t, h), v)| SensorReading { 
            temperature: t,
            humidity: h,
            voltage: v,
        })
        .collect();

    println!("Combined Readings:");
    for reading in &combined_readings {
        println!("T: {:.1}, H: {:.1}, V: {:.2}", 
                 reading.temperature, reading.humidity, reading.voltage);
    }

    let temps_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.temperature)
        .collect();

    let hums_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.humidity)
        .collect();

    let vols_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.voltage)
        .collect();

    println!("nUnzipped Temperature Readings (First 2): ");
    for i in 0..std::cmp::min(2, temps_only.len()) {
        println!("{:.1}", temps_only[i]);
    }
}
